20→/** @file*/
21→
22→#include "internal_nn_math.h"
23→#include "riscv_nn_support.h"
24→
25→//// FullyConnected Functions
26→void riscv_nn_fc_mat_vec_s8_wt_converter(const q7_t *wt_mat,
27→                                        const uint32_t size,
28→                                        const uint32_t wt_row_num,
29→                                        q7_t *wt_mat_out)
30→{
31→    long row, col;
32→    int8_t *ptr1 = (int8_t*)wt_mat,
33→           *ptr2 = ptr1 + size,
34→           *ptr3 = ptr2 + size,
35→           *ptr4 = ptr3 + size,
36→           *out = wt_mat_out;
37→
38→    row = wt_row_num >> 2;
39→    while(row-- > 0)
40→    {
41→        col = size >> 1;
42→        while(col-- > 0)
43→        {
44→            *out++ = *ptr1++;
45→            *out++ = *ptr2++;
46→            *out++ = *ptr1++;
47→            *out++ = *ptr2++;
48→
49→            *out++ = *ptr3++;
50→            *out++ = *ptr4++;
51→            *out++ = *ptr3++;
52→            *out++ = *ptr4++;
53→        }
54→
55→        if(size & 0x1)
56→        {
57→           *out++ = *ptr1++;
58→           *out++ = *ptr2++;
59→           *out++ = *ptr3++;
60→           *out++ = *ptr4++;
61→        }
62→
63→        ptr1 += size * 3;
64→        ptr2 += size * 3;
65→        ptr3 += size * 3;
66→        ptr4 += size * 3;
67→    }
68→
69→    row = wt_row_num & 3;
70→    long reset_length = row * size;
71→    memcpy(out, ptr1, reset_length * sizeof(*wt_mat));
72→}
