25→//// FullyConnected Functions
26→void riscv_nn_fc_s8_wt_converter(const q7_t *wt_mat,
27→                                const uint32_t size,
28→                                const uint32_t wt_row_num,
29→                                q7_t *wt_mat_out)
30→{
31→    long row, col;
32→    q7_t *ptr1 = (q7_t*)wt_mat,
33→         *ptr2 = ptr1 + size,
34→         *ptr3 = ptr2 + size,
35→         *ptr4 = ptr3 + size,
36→         *out = wt_mat_out;
37→
38→    row = wt_row_num >> 2;
39→    while(row-- > 0)
40→    {
41→        col = size >> 2;
42→        while(col-- > 0)
43→        {
44→            *out++ = *ptr1;
45→            *out++ = *ptr2;
46→            *out++ = *(ptr1+2);
47→            *out++ = *(ptr2+2);
48→
49→            *out++ = *ptr3;
50→            *out++ = *ptr4;
51→            *out++ = *(ptr3+2);
52→            *out++ = *(ptr4+2);
53→
54→            *out++ = *(ptr1+1);
55→            *out++ = *(ptr2+1);
56→            *out++ = *(ptr1+3);
57→            *out++ = *(ptr2+3);
58→
59→            *out++ = *(ptr3+1);
60→            *out++ = *(ptr4+1);
61→            *out++ = *(ptr3+3);
62→            *out++ = *(ptr4+3);
63→
64→            ptr1 += 4;
65→            ptr2 += 4;
66→            ptr3 += 4;
67→            ptr4 += 4;
68→        }
69→
70→        col = size & 3;
71→        while(col-- > 0)
72→        {
73→           *out++ = *ptr1++;
74→           *out++ = *ptr2++;
75→           *out++ = *ptr3++;
76→           *out++ = *ptr4++;
77→        }
78→
79→        ptr1 += size * 3;
80→        ptr2 += size * 3;
81→        ptr3 += size * 3;
82→        ptr4 += size * 3;
83→    }
84→
85→    row = wt_row_num & 3;
86→    long reset_length = row * size;
87→    memcpy(out, ptr1, reset_length * sizeof(*wt_mat));
88→}

