  20→/** @file*/
  21→
  22→#include "internal_nn_math.h"
  23→#include "riscv_nn_support.h"
  24→
  25→//// FullyConnected Functions
  26→
  27→int32_t riscv_nn_fc_s8_s8_s8_sft_bias_fast(const q7_t * in_vec,
  28→                        const q7_t * wt_mat,
  29→                        const uint16_t size,
  30→                        const uint16_t wt_row_num,
  31→                        const uint16_t bias_lshift,
  32→                        const uint16_t out_rshift,
  33→                        const q7_t * bias,
  34→                        q7_t * out_vec,
  35→                        q15_t * in_tmp_buf)
  36→{
  37→#ifdef ENA_EMPTY_FUN
  38→    //empty body
  39→#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_ISA_ZVQMAC) && defined(ENA_VEC_INTRINSIC)
  40→    const q7_t *pB = wt_mat;
  41→    const q7_t *pBias = bias;
  42→    q7_t *pO = out_vec;
  43→    const q7_t *pA;
  44→    int32_t vl;
  45→    uint32_t rowCnt = wt_row_num >> 2;
  46→    uint32_t colCnt = (size >> 2) << 4;
  47→
  48→    nn_dup_s8_x4_reordered(in_vec, (q7_t*)in_tmp_buf, size);
  49→
  50→    //generate acc reduction mask
  51→    //Note. each element only occupy 1 bit
  52→    const uint64_t base_mask = 0x1111111111111111;
  53→    const uint64_t mask_1 = 0x1817161514111211;
  54→    const uint64_t mask_2 = 0x1817161511131112;
  55→    const uint64_t mask_3 = 0x1811161115141312;
  56→    const uint64_t mask_4 = 0x1118111615141312;
  57→    vl = __riscv_vsetvl_e64m8((colCnt+7)>>3);
  58→    vuint64m2_t vBase_mask_u64 = __riscv_vundefined_u64m2();
  59→    vuint64m2_t vA1 = __riscv_vundefined_u64m2();
  60→    vuint64m2_t vA2 = __riscv_vundefined_u64m2();
  61→    vuint64m2_t vA3 = __riscv_vundefined_u64m2();
  62→    vuint64m2_t vA4 = __riscv_vundefined_u64m2();
  63→    vBase_mask_u64 = __riscv_vmv_v_tu(vBase_mask_u64, base_mask, vl);
  64→    vA1 = __riscv_vmv_v_tu(vA1, mask_1, vl);
  65→    vA2 = __riscv_vmv_v_tu(vA2, mask_2, vl);
  66→    vA3 = __riscv_vmv_v_tu(vA3, mask_3, vl);
  67→    vA4 = __riscv_vmv_v_tu(vA4, mask_4, vl);
  68→    vuint8m2_t vBase_interpret = __riscv_vreinterpret_u8m2(vBase_mask_u64);
  69→    vuint8m2_t vInterpret_1 = __riscv_vreinterpret_u8m2(vA1);
  70→    vuint8m2_t vInterpret_2 = __riscv_vreinterpret_u8m2(vA2);
  71→    vuint8m2_t vInterpret_3 = __riscv_vreinterpret_u8m2(vA3);
  72→    vuint8m2_t vInterpret_4 = __riscv_vreinterpret_u8m2(vA4);
  73→    vl = __riscv_vsetvl_e8m2(colCnt);
  74→    vbool4_t vMask1_b4 = __riscv_vmseq(vBase_interpret, vInterpret_1, vl);   //8n   8n+1 index mask (for acc1)
  75→    vbool4_t vMask2_b4 = __riscv_vmseq(vBase_interpret, vInterpret_2, vl);   //8n+2 8n+3 index mask (for acc2)
  76→    vbool4_t vMask3_b4 = __riscv_vmseq(vBase_interpret, vInterpret_3, vl);   //8n+4 8n+5 index mask (for acc3)
  77→    vbool4_t vMask4_b4 = __riscv_vmseq(vBase_interpret, vInterpret_4, vl);   //8n+6 8n+7 index mask (for acc4)
  78→
  79→    while (rowCnt)
  80→    {
  81→        //set SEW for 1st time VMV_S_X
  82→        //LMUL=8 is just for clear v8~v15 (vmv ignores LMUL)
  83→        vl = __riscv_vsetvl_e32m8(colCnt);
  84→
  85→        uint32_t colCnt2 = colCnt;
  86→        pA = (q7_t*)in_tmp_buf;
  87→        /* init sum with bias */
  88→        int32_t sum  = ((q31_t)(*pBias++) << bias_lshift) + NN_ROUND(out_rshift);
  89→        int32_t sum2 = ((q31_t)(*pBias++) << bias_lshift) + NN_ROUND(out_rshift);
  90→        int32_t sum3 = ((q31_t)(*pBias++) << bias_lshift) + NN_ROUND(out_rshift);
  91→        int32_t sum4 = ((q31_t)(*pBias++) << bias_lshift) + NN_ROUND(out_rshift);
  92→
  93→        //init
  94→        vint32m1_t vSum1_i32 = __riscv_vmv_s_x_i32m1(sum, vl);
  95→        vint32m1_t vSum2_i32 = __riscv_vmv_s_x_i32m1(sum2, vl);
  96→        vint32m1_t vSum3_i32 = __riscv_vmv_s_x_i32m1(sum3, vl);
  97→        vint32m1_t vSum4_i32 = __riscv_vmv_s_x_i32m1(sum4, vl);
  98→        //clear acc
  99→        vint32m8_t vAcc_i32 = __riscv_vundefined_i32m8();
 100→        vAcc_i32 = __riscv_vand_tu(vAcc_i32, vAcc_i32, 0, vl);
 101→
 102→        while(colCnt2)
 103→        {
 104→            vl = __riscv_vsetvl_e8m2(colCnt2);
 105→            vint8m2_t vpA_i8 = __riscv_vundefined_i8m2();
 106→            vint8m2_t vpB_i8m2 = __riscv_vundefined_i8m2();
 107→            vpA_i8 = __riscv_vle8_tu(vpA_i8, pA, vl);
 108→            vpB_i8m2 = __riscv_vle8_tu(vpB_i8m2, pB, vl);
 109→            vAcc_i32 = __riscv_vqmacc_vv_i32m8_tu(vAcc_i32, vpA_i8, vpB_i8m2, vl);
 110→            colCnt2 -= vl;
 111→            pA += vl;
 112→            pB += vl;
 113→        }
 114→
 115→        vl = __riscv_vsetvl_e32m8(colCnt);  //note the avl here
 116→        vint32m1_t vRedsum1_i32 = __riscv_vredsum(vMask1_b4, vAcc_i32, vSum1_i32, vl);
 117→        vint32m1_t vRedsum2_i32 = __riscv_vredsum(vMask2_b4, vAcc_i32, vSum2_i32, vl);
 118→        vint32m1_t vRedsum3_i32 = __riscv_vredsum(vMask3_b4, vAcc_i32, vSum3_i32, vl);
 119→        vint32m1_t vRedsum4_i32 = __riscv_vredsum(vMask4_b4, vAcc_i32, vSum4_i32, vl);
 120→
 121→        //rest part
 122→        vl = __riscv_vsetvl_e32m1(4);     //4: 4 acc
 123→        vRedsum1_i32 = __riscv_vslideup(vRedsum1_i32, vRedsum2_i32, 1, vl);
 124→        vRedsum1_i32 = __riscv_vslideup(vRedsum1_i32, vRedsum3_i32, 2, vl);
 125→        vRedsum1_i32 = __riscv_vslideup(vRedsum1_i32, vRedsum4_i32, 3, vl);
 126→
 127→        vl = __riscv_vsetvl_e8mf4(4);     //4: 4 acc
 128→        colCnt2 = size & 0x3;
 129→        while(colCnt2)
 130→        {
 131→            q7_t inV = *pA++;
 132→            vint8mf4_t vpB_i8mf4 = __riscv_vundefined_i8mf4();
 133→            vpB_i8mf4 = __riscv_vle8_tu(vpB_i8mf4, pB, vl);
 134→            vRedsum1_i32 = __riscv_vqmacc_vx_i32m1_tu(vRedsum1_i32, inV, vpB_i8mf4, vl);
 135→            pB += 4;
 136→            colCnt2--;
 137→        }
 138→
 139→        vl = __riscv_vsetvl_e32m1(4);     //4: 4 acc
 140→        vRedsum1_i32 = __riscv_vsra(vRedsum1_i32, out_rshift, vl);
 141→        vRedsum1_i32 = __riscv_vmax(vRedsum1_i32, Q7_MIN, vl);
 142→        vRedsum1_i32 = __riscv_vmin(vRedsum1_i32, Q7_MAX, vl);
 143→
 144→        vl = __riscv_vsetvl_e16mf2(4);
 145→        vint16mf2_t vResult_i16 = __riscv_vundefined_i16mf2();
 146→        vResult_i16 = __riscv_vnsra(vRedsum1_i32, 0, vl);
 147→        vl = __riscv_vsetvl_e8mf4(4);
 148→        vint8mf4_t vResult_i8 = __riscv_vundefined_i8mf4();
 149→        vResult_i8 = __riscv_vnsra(vResult_i16, 0, vl);
 150→        __riscv_vse8(pO, vResult_i8, vl);
 151→        pO += 4;
 152→        rowCnt--;
 153→    }
 154→
 155→    vl = __riscv_vsetvl_e32m8(size);
 156→    rowCnt = wt_row_num & 0x3;
 157→    while (rowCnt)
 158→    {
 159→        int32_t sum = ((q31_t)(*pBias++) << bias_lshift) + NN_ROUND(out_rshift);
 160→        pA = in_vec;
 161→        colCnt = size;
 162→
 163→        vint32m8_t vAcc_i32 = __riscv_vundefined_i32m8();
 164→        //init
 165→        vint32m1_t vSum1_i32 = __riscv_vmv_s_x_i32m1(sum, vl);
 166→        //clear acc
 167→        vAcc_i32 = __riscv_vand_tu(vAcc_i32, vAcc_i32, 0, vl);
 168→
 169→        while (colCnt != 0)
 170→        {
 171→            vl = __riscv_vsetvl_e8m2(colCnt);
 172→            vint8m2_t vpA_i8 = __riscv_vundefined_i8m2();
 173→            vint8m2_t vpB_i8m2 = __riscv_vundefined_i8m2();
 174→            vpA_i8 = __riscv_vle8_tu(vpA_i8, pA, vl);
 175→            vpB_i8m2 = __riscv_vle8_tu(vpB_i8m2, pB, vl);
 176→            vAcc_i32 = __riscv_vqmacc_vv_i32m8_tu(vAcc_i32, vpA_i8, vpB_i8m2, vl);
 177→            pB += vl;
 178→            pA += vl;
 179→            colCnt -= vl;
 180→        }
 181→
 182→        vl = __riscv_vsetvl_e32m8(size);
 183→        vint32m1_t vRedsum1_i32 = __riscv_vredsum(vAcc_i32, vSum1_i32, vl);
 184→        sum = __riscv_vmv_x(vRedsum1_i32);
 185→        *pO++ = NDS_ISA_SATS((sum >> out_rshift), 8);
 186→        rowCnt--;
 187→    }
 188→#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_ISA_ZVQMAC)
 189→    const q7_t *pB = wt_mat;
 190→    const q7_t *pBias = bias;
 191→    q7_t *pO = out_vec;
 192→    const q7_t *pA;
 193→    int32_t vl;
 194→    uint32_t rowCnt = wt_row_num >> 2;
 195→    uint32_t colCnt = (size >> 2) << 4;
 196→
 197→    nn_dup_s8_x4_reordered(in_vec, (q7_t*)in_tmp_buf, size);
 198→
 199→    //generate acc reduction mask
 200→    //Note. each element only occupy 1 bit
 201→    NDS_VEC_VSETVLI_E8(vl, (colCnt+7)>>3);
 202→    NDS_VEC_VAND_VX(NDS_VEC_V0, NDS_VEC_V0, 0);
 203→    NDS_VEC_VOR_VX(NDS_VEC_V20, NDS_VEC_V0, 0x05);   //8n   8n+2 index mask (for acc1)
 204→    NDS_VEC_VOR_VX(NDS_VEC_V21, NDS_VEC_V0, 0x0A);   //8n+1 8n+3 index mask (for acc2)
 205→    NDS_VEC_VOR_VX(NDS_VEC_V22, NDS_VEC_V0, 0x50);   //8n+4 8n+6 index mask (for acc3)
 206→    NDS_VEC_VOR_VX(NDS_VEC_V23, NDS_VEC_V0, 0xA0);   //8n+5 8n+7 index mask (for acc4)
 207→
 208→    while (rowCnt)
 209→    {
 210→        //set SEW for 1st time VMV_S_X
 211→        //LMUL=8 is just for clear v8~v15 (vmv ignores LMUL)
 212→        NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
 213→
 214→        uint32_t colCnt2 = colCnt;
 215→        pA = (q7_t*)in_tmp_buf;
 216→        /* init sum with bias */
 217→        int32_t sum  = ((q31_t)(*pBias++) << bias_lshift) + NN_ROUND(out_rshift);
 218→        int32_t sum2 = ((q31_t)(*pBias++) << bias_lshift) + NN_ROUND(out_rshift);
 219→        int32_t sum3 = ((q31_t)(*pBias++) << bias_lshift) + NN_ROUND(out_rshift);
 220→        int32_t sum4 = ((q31_t)(*pBias++) << bias_lshift) + NN_ROUND(out_rshift);
 221→
 222→        //init
 223→        NDS_VEC_VMV_S_X(NDS_VEC_V16, sum);
