1043→            inB = *pB++;
1044→            sum2 += inA * inB;
1045→            inB = *pB++;
1046→            sum3 += inA * inB;
1047→            inB = *pB++;
1048→            sum4 += inA * inB;
1049→
1050→            colCnt--;
1051→        }
1052→        *pO++ = (q7_t) NDS_ISA_SATS((sum >> out_rshift), 8);
1053→        *pO++ = (q7_t) NDS_ISA_SATS((sum2 >> out_rshift), 8);
1054→        *pO++ = (q7_t) NDS_ISA_SATS((sum3 >> out_rshift), 8);
1055→        *pO++ = (q7_t) NDS_ISA_SATS((sum4 >> out_rshift), 8);
1056→
1057→        rowCnt--;
1058→    }
1059→
1060→    rowCnt = wt_row_num & 0x3;
1061→
1062→    while (rowCnt)
1063→    {
1064→        int ip_out = ((q31_t)(*pBias++) << bias_lshift) + NN_ROUND(out_rshift);
1065→        int j;
1066→
1067→        pA = in_vec;
1068→        for (j = 0; j < size; j++)
1069→        {
1070→            q7_t      inA = *pA++;
1071→            q7_t      inB = *pB++;
1072→            ip_out += inA * inB;
1073→        }
1074→        *pO++ = (q7_t) NDS_ISA_SATS((ip_out >> out_rshift), 8);
1075→
1076→        rowCnt--;
1077→    }
1078→
1079→#endif                          /* ENA_DSP_ISA */
1080→
1081→    return 0;
1082→}
