 98→
 99→        vRedsum1_i32 = __riscv_vadd(vRedsum1_i32, dst_offset, vl);
100→
101→        // Clamp the result
102→        vRedsum1_i32 = __riscv_vmax(vRedsum1_i32, activation_min, vl);
103→        vRedsum1_i32 = __riscv_vmin(vRedsum1_i32, activation_max, vl);
104→
105→        //narrowing and store the results
106→        vl = __riscv_vsetvl_e16mf2(vl);
107→        vint16mf2_t vRedsum1_i16 = __riscv_vnsra(vRedsum1_i32, 0, vl);
108→        vl = __riscv_vsetvl_e8mf4(vl);
