114→
115→    if (rhs_rows & 1)
116→    {
117→        const q7_t *lhs_ptr = &lhs[0];
118→        const q7_t *rhs_ptr = &rhs[0];
119→
120→        vl = __riscv_vsetvl_e32m1(1);
121→        vint32m1_t vBias = __riscv_vundefined_i32m1();
122→        vBias = __riscv_vand(vBias, 0, vl);
123→        if(bias != NULL)
124→        {
125→            vBias = __riscv_vle32_v_i32m1(bias, vl);
126→            bias++;
127→        }
128→        vl = __riscv_vsetvl_e32m8(rhs_cols);
129→        vint32m8_t vResult1 = __riscv_vundefined_i32m8();
130→        vResult1 = __riscv_vand(vResult1, 0, vl);     //for keeping vwmacc results
131→
132→        long rhs_cols2 = rhs_cols;
133→        while(rhs_cols2 > 0)
134→        {
135→            vl = __riscv_vsetvl_e8m2(rhs_cols2);
136→            vint8m2_t vRhs_i8 = __riscv_vle8_v_i8m2(rhs_ptr, vl);                    //*rhs_ptr
137→            vint8m2_t vLhs_i8 = __riscv_vle8_v_i8m2(lhs_ptr, vl);                    //*lhs_ptr
138→            vl = __riscv_vsetvl_e16m4(rhs_cols2);
139→            vint16m4_t vRhs_i16 = __riscv_vsext_vf2(vRhs_i8, vl);
140→            vint16m4_t vLhs_i16 = __riscv_vsext_vf2(vLhs_i8, vl);
141→            vRhs_i16 = __riscv_vadd(vRhs_i16, rhs_offset, vl);    //*rhs_ptr + rhs_offset
142→            vLhs_i16 = __riscv_vadd(vLhs_i16, lhs_offset, vl);    //*lhs_ptr + lhs_offset
143→            vResult1 = __riscv_vwmacc(vResult1, vRhs_i16, vLhs_i16, vl);
144→            rhs_ptr += vl;
145→            lhs_ptr += vl;
146→            rhs_cols2 -= vl;
147→        }
