 22→int32_t nn_vec_mat_mult_t_per_ch_s8(const int8_t *lhs,
 23→                                    const int8_t *rhs,
 24→                                    const int32_t *kernel_sum,
 25→                                    const int32_t *bias,
 26→                                    int8_t *dst,
 27→                                    const int32_t lhs_offset,
 28→                                    const int32_t dst_offset,
 29→                                    const int32_t *dst_multiplier,
 30→                                    const int32_t *dst_shift,
 31→                                    const int32_t rhs_cols,
 32→                                    const int32_t rhs_rows,
 33→                                    const int32_t activation_min,
 34→                                    const int32_t activation_max,
 35→                                    const int32_t address_offset,
 36→                                    const int32_t rhs_offset)
 37→{
 38→    (void)kernel_sum;
 39→
 40→    if (rhs_offset)
 41→    {
 42→        const int32_t row_loop_cnt = rhs_rows / 3;
 43→
 44→        for (int32_t i_row_loop_cnt = 0; i_row_loop_cnt < row_loop_cnt; i_row_loop_cnt++)
 45→        {
 46→            const int8_t *lhs_ptr = lhs;
 47→            const int8_t *rhs_ptr_0 = &rhs[0];
 48→            const int8_t *rhs_ptr_1 = &rhs[rhs_cols];
 49→            const int8_t *rhs_ptr_2 = &rhs[rhs_cols * 2];
 50→
 51→            int32_t res00 = 0;
 52→            int32_t res01 = 0;
 53→            int32_t res02 = 0;
 54→            if (bias)
 55→            {
 56→                res00 = *bias++;
 57→                res01 = *bias++;
 58→                res02 = *bias++;
 59→            }
 60→            for (int32_t rhs_cols_idx = 0; rhs_cols_idx < rhs_cols; ++rhs_cols_idx)
 61→            {
 62→                const int32_t rhs_value0 = (int8_t)*rhs_ptr_0 + rhs_offset;
 63→                const int32_t rhs_value1 = (int8_t)*rhs_ptr_1 + rhs_offset;
 64→                const int32_t rhs_value2 = (int8_t)*rhs_ptr_2 + rhs_offset;
 65→                const int32_t lhs_value = (int8_t)*lhs_ptr + lhs_offset;
 66→
 67→                res00 += lhs_value * rhs_value0;
 68→                res01 += lhs_value * rhs_value1;
 69→                res02 += lhs_value * rhs_value2;
 70→
 71→                ++rhs_ptr_0;
 72→                ++rhs_ptr_1;
 73→                ++rhs_ptr_2;
 74→                ++lhs_ptr;
 75→            }
 76→
 77→            // Quantize down
 78→            res00 = nn_requantize(res00, *dst_multiplier++, *dst_shift++);
 79→            res01 = nn_requantize(res01, *dst_multiplier++, *dst_shift++);
 80→            res02 = nn_requantize(res02, *dst_multiplier++, *dst_shift++);
 81→
 82→            // Add offset
 83→            res00 += dst_offset;
 84→            res01 += dst_offset;
 85→            res02 += dst_offset;
 86→
 87→            // Clamp the result
 88→            res00 = MAX(res00, activation_min);
 89→            res00 = MIN(res00, activation_max);
 90→            res01 = MAX(res01, activation_min);
 91→            res01 = MIN(res01, activation_max);
 92→            res02 = MAX(res02, activation_min);
 93→            res02 = MIN(res02, activation_max);
 94→
 95→            *dst = (int8_t)res00;
 96→            *(dst + address_offset) = (int8_t)res01;
 97→            *(dst + 2 * address_offset) = (int8_t)res02;
 98→            dst += 3 * address_offset;
 99→
100→            rhs += 3 * rhs_cols;
101→        }
102→
103→        const int loop_cnt = rhs_rows % 3;
104→
105→        for (int32_t i_loop_cnt = 0; i_loop_cnt < loop_cnt; i_loop_cnt++)
106→        {
107→            const int8_t *lhs_ptr = &lhs[0];
108→            const int8_t *rhs_ptr = &rhs[0];
109→
110→            int32_t res00 = 0;
111→            if (bias)
112→            {
113→                res00 = *bias++;
114→            }
115→
116→            for (int32_t rhs_cols_idx = 0; rhs_cols_idx < rhs_cols; ++rhs_cols_idx)
117→            {
118→                int32_t rhs_value0 = (int8_t)rhs_ptr[0] + rhs_offset;
119→                int32_t lhs_value = (int8_t)lhs_ptr[0] + lhs_offset;
120→
121→                res00 += lhs_value * rhs_value0;
122→
123→                ++rhs_ptr;
124→                ++lhs_ptr;
125→            }
126→
127→            // Quantize down
128→            res00 = nn_requantize(res00, *dst_multiplier++, *dst_shift++);
129→
130→            // Add offset
131→            res00 += dst_offset;
132→
133→            // Clamp the result
134→            res00 = MAX(res00, activation_min);
135→            res00 = MIN(res00, activation_max);
136→
137→            *dst = (int8_t)res00;
138→            dst += address_offset;
139→            rhs += rhs_cols;
140→        }
141→    }
142→    else
143→    {
144→        const int32_t row_loop_cnt = rhs_rows / 3;
145→
146→        for (int32_t i_row_loop_cnt = 0; i_row_loop_cnt < row_loop_cnt; i_row_loop_cnt++)
147→        {
148→            const int8_t *lhs_ptr = lhs;
149→            const int8_t *rhs_ptr_0 = &rhs[0];
150→            const int8_t *rhs_ptr_1 = &rhs[rhs_cols];

