 22→int32_t nn_vec_mat_mult_t_s16(const int16_t *lhs,
 23→                              const int8_t *rhs,
 24→                              const int64_t *bias,
 25→                              int16_t *dst,
 26→                              // const int32_t lhs_offset,
 27→                              // const int32_t rhs_offset,
 28→                              // const int32_t dst_offset,
 29→                              const int32_t dst_multiplier,
 30→                              const int32_t dst_shift,
 31→                              const int32_t rhs_cols,
 32→                              const int32_t rhs_rows,
 33→                              const int32_t activation_min,
 34→                              const int32_t activation_max)
 35→{
 36→#if defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD) && defined(ENA_VEC_INTRINSIC)
 37→    long dst_shift2 = 14 - dst_shift;
 38→    long rhs_rows2 = rhs_rows >> 1;
 39→    long vl;
 40→    long vlenb = NDS_VEC_CSR_GET_VLENB();
 41→    vl = __riscv_vsetvl_e64m1(1);
 42→    vint64m1_t vZero = __riscv_vundefined_i64m1();
 43→    vZero = __riscv_vand_tu(vZero, vZero, 0, vl);    //const zero for redsum
 44→
 45→    while (rhs_rows2-- > 0)
 46→    {
 47→        const int16_t *lhs_ptr = lhs;
 48→        const int8_t  *rhs_ptr = &rhs[0];
 49→        const int8_t  *rhs_ptr2 = &rhs[rhs_cols];
 50→
 51→        vl = __riscv_vsetvl_e64m4(rhs_cols);
 52→        vint64m4_t vAcc0 = __riscv_vundefined_i64m4();
 53→        vint64m4_t vAcc1 = __riscv_vundefined_i64m4();
 54→        vAcc0 = __riscv_vand_tu(vAcc0, vAcc0, 0, vl);
 55→        vAcc1 = __riscv_vand_tu(vAcc1, vAcc1, 0, vl);
 56→
 57→        long rhs_cols2 = rhs_cols;
 58→        while(rhs_cols2 >= ((vlenb >> 1) * NDS_VEC_VTYPE_LMUL_ID_M4))
 59→        {
 60→            vl = __riscv_vsetvl_e8m2(rhs_cols2);
 61→            vint8m2_t vRhs_i8 = __riscv_vle8_v_i8m2(rhs_ptr, vl);
 62→            vint8m2_t vRhs2_i8 = __riscv_vle8_v_i8m2(rhs_ptr2, vl);
 63→            vl = __riscv_vsetvl_e16m4(rhs_cols2);
 64→            vint16m4_t vLhs_i16 = __riscv_vle16_v_i16m4(lhs_ptr, vl);
 65→            vint16m4_t vRhs_i16 = __riscv_vsext_vf2(vRhs_i8, vl);
 66→            vint16m4_t vRhs2_i16 = __riscv_vsext_vf2(vRhs2_i8, vl);
 67→            rhs_ptr += vl;
 68→            rhs_ptr2 += vl;
 69→            lhs_ptr += vl;
 70→            rhs_cols2 -= vl;
 71→
 72→            vl >>= 2;
 73→            vl = __riscv_vsetvl_e64m4(vl);
 74→            vAcc0 = __riscv_vd4dots_vv_i64m4(vAcc0, vRhs_i16, vLhs_i16, vl);
 75→            vAcc1 = __riscv_vd4dots_vv_i64m4(vAcc1, vRhs2_i16, vLhs_i16, vl);
 76→        }
 77→
 78→        //extra process for the case of elements to be dot producted is not a mutiple of 4
 79→        if(rhs_cols2 > 0)
 80→        {
 81→            //clean one of the dot product source
 82→            long tmp_avl = rhs_cols2 + 3;
 83→            vl = __riscv_vsetvl_e16m4(tmp_avl);
 84→            vint16m4_t vLhs_i16 = __riscv_vundefined_i16m4();
 85→			vLhs_i16 = __riscv_vand_tu(vLhs_i16, vLhs_i16, 0, vl);
 86→
 87→            vl = __riscv_vsetvl_e8m2(rhs_cols2);
 88→            vint8m2_t vRhs_i8 = __riscv_vundefined_i8m2();
 89→            vint8m2_t vRhs2_i8 = __riscv_vundefined_i8m2();
 90→            vRhs_i8 = __riscv_vle8_tu(vRhs_i8, rhs_ptr, vl);
 91→            vRhs2_i8 = __riscv_vle8_tu(vRhs2_i8, rhs_ptr2, vl);
 92→
 93→            vl = __riscv_vsetvl_e16m4(rhs_cols2);
 94→            vLhs_i16 = __riscv_vle16_tu(vLhs_i16, lhs_ptr, vl);
 95→            vint16m4_t vRhs_i16 = __riscv_vundefined_i16m4();
 96→            vint16m4_t vRhs2_i16 = __riscv_vundefined_i16m4();
 97→            vRhs_i16 = __riscv_vsext_vf2_tu(vRhs_i16, vRhs_i8, vl);
 98→            vRhs2_i16 = __riscv_vsext_vf2_tu(vRhs2_i16, vRhs2_i8, vl);
 99→            rhs_ptr += vl;
100→            rhs_ptr2 += vl;
101→            lhs_ptr += vl;
102→            rhs_cols2 -= vl;
103→
104→            vl = (vl + 3) >> 2;
105→            vl = __riscv_vsetvl_e64m4(vl);
106→            vAcc0 = __riscv_vd4dots_vv_i64m4_tu(vAcc0, vRhs_i16, vLhs_i16, vl);
107→            vAcc1 = __riscv_vd4dots_vv_i64m4_tu(vAcc1, vRhs2_i16, vLhs_i16, vl);
108→        }
109→
110→        vl = __riscv_vsetvl_e64m4(rhs_cols);    //note the avl here
111→        vint64m1_t vAcc0_sum = __riscv_vredsum(vAcc0, vZero, vl);
112→		vint64m1_t vAcc1_sum = __riscv_vredsum(vAcc1, vZero, vl);
113→
114→        vl = __riscv_vsetvl_e64m1(2);
115→        vAcc0_sum = __riscv_vslideup(vAcc0_sum, vAcc1_sum, 1, vl);
116→
117→        if (bias)
118→        {
119→            vint64m1_t vBias = __riscv_vundefined_i64m1();
120→            vBias = __riscv_vle64_v_i64m1(bias, vl);
121→            vAcc0_sum = __riscv_vadd(vAcc0_sum, vBias, vl);
122→            bias += vl;
123→        }
124→
125→        // requantize_s64
126→        vAcc0_sum = __riscv_vmul(vAcc0_sum, dst_multiplier, vl);
127→        vl = __riscv_vsetvl_e32mf2(vl);
128→        vint32mf2_t vAcc0_sum_i32 = __riscv_vundefined_i32mf2();
129→        vAcc0_sum_i32 = __riscv_vnsra(vAcc0_sum, dst_shift2, vl);
130→        vAcc0_sum_i32 = __riscv_vssra(vAcc0_sum_i32, 1, __RISCV_VXRM_RNU, vl);
131→
132→        vAcc0_sum_i32 = __riscv_vmax(vAcc0_sum_i32, activation_min, vl);
133→        vAcc0_sum_i32 = __riscv_vmin(vAcc0_sum_i32, activation_max, vl);
134→        vl = __riscv_vsetvl_e16mf4(vl);
135→        vint16mf4_t vAcc0_sum_i16 = __riscv_vundefined_i16mf4();
136→        vAcc0_sum_i16 = __riscv_vnsra(vAcc0_sum_i32, 0, vl);
137→        __riscv_vse16(dst, vAcc0_sum_i16, vl);
138→        dst += vl;
139→        rhs += rhs_cols * 2;
140→    }
141→
142→    if (rhs_rows & 1)
143→    {
144→        const int16_t *lhs_ptr = lhs;
145→        const int8_t  *rhs_ptr = &rhs[0];
146→
147→        int64_t acc_s64 = 0;
148→
149→        vl = __riscv_vsetvl_e64m8(rhs_cols);
150→        vint64m8_t vAcc0 = __riscv_vundefined_i64m8();
